/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering per notification type (HTML email bodies)
 * - Recipient email validation
 * - Configurable sender identity
 * - In-memory send log for testing
 *
 * Implements NotificationAdapter so the NotificationService can
 * route email-channel notifications here.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender address shown in the From field. */
  fromAddress: string;
  /** Display name for the sender. */
  fromName: string;
}

const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
};

export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  body: string;
  html: string;
  sentAt: Date;
}

/**
 * Email templates keyed by notification type.
 * Each template receives the payload and returns an HTML string.
 */
const emailTemplates: Record<NotificationType, (payload: NotificationPayload) => string> = {
  order_confirmation(payload) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    return `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #2c3e50;">Order Confirmation</h2>
  <p>Thank you for your order <strong>${orderId}</strong>!</p>
  <div style="background: #f8f9fa; padding: 16px; border-radius: 4px;">
    ${payload.body}
  </div>
  <p style="color: #7f8c8d; font-size: 12px; margin-top: 24px;">
    This is an automated message from TaskFlow Pro. Please do not reply.
  </p>
</div>`;
  },

  order_status_update(payload) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const newStatus = (payload.metadata?.newStatus as string) ?? '';
    return `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #2c3e50;">Order Status Update</h2>
  <p>Your order <strong>${orderId}</strong> has been updated.</p>
  <div style="background: #f8f9fa; padding: 16px; border-radius: 4px;">
    <p><strong>New Status:</strong> ${newStatus}</p>
    <p>${payload.body}</p>
  </div>
  <p style="color: #7f8c8d; font-size: 12px; margin-top: 24px;">
    This is an automated message from TaskFlow Pro. Please do not reply.
  </p>
</div>`;
  },

  user_welcome(payload) {
    return `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #2c3e50;">Welcome to TaskFlow Pro!</h2>
  <p>${payload.body}</p>
  <div style="background: #f8f9fa; padding: 16px; border-radius: 4px;">
    <p>Here are some things you can do to get started:</p>
    <ul>
      <li>Browse our product catalog</li>
      <li>Place your first order</li>
      <li>Update your profile settings</li>
    </ul>
  </div>
  <p style="color: #7f8c8d; font-size: 12px; margin-top: 24px;">
    This is an automated message from TaskFlow Pro. Please do not reply.
  </p>
</div>`;
  },

  user_updated(payload) {
    return `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #2c3e50;">Account Updated</h2>
  <p>${payload.body}</p>
  <p style="color: #7f8c8d; font-size: 12px; margin-top: 24px;">
    This is an automated message from TaskFlow Pro. Please do not reply.
  </p>
</div>`;
  },
};

/** Basic email address validation. */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Render the notification body into an HTML email using
   * the appropriate template for the notification type.
   */
  renderTemplate(payload: NotificationPayload): string {
    const templateFn = emailTemplates[payload.notificationType];
    return templateFn(payload);
  }

  /**
   * Resolve and validate the recipient email address.
   * Returns the validated email or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const email = payload.recipient.trim().toLowerCase();
    if (!email || !isValidEmail(email)) {
      this.logger.warn(`Invalid recipient email address: "${payload.recipient}"`);
      return null;
    }
    return email;
  }

  /**
   * Send an email notification.
   *
   * 1. Validates the recipient address.
   * 2. Renders the HTML body from templates.
   * 3. Records the email (in-memory for testing; swap for real provider in production).
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    try {
      const recipient = this.resolveRecipient(payload);
      if (!recipient) {
        return false;
      }

      const html = this.renderTemplate(payload);
      const from = `${this.config.fromName} <${this.config.fromAddress}>`;

      this.logger.info(`Sending email from "${from}" to ${recipient}: ${payload.subject}`);

      this.sentEmails.push({
        to: recipient,
        from,
        subject: payload.subject,
        body: payload.body,
        html,
        sentAt: new Date(),
      });

      return true;
    } catch (error) {
      this.logger.error(
        `Failed to send email to ${payload.recipient}: ${error instanceof Error ? error.message : String(error)}`,
      );
      return false;
    }
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    notificationType: 'order_confirmation',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('send', () => {
    it('should send an email and return true on success', async () => {
      const result = await adapter.send(makePayload());

      expect(result).toBe(true);
      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should normalize recipient email to lowercase', async () => {
      await adapter.send(makePayload({ recipient: 'Alice@Example.COM' }));

      const sent = adapter.getSentEmails();
      expect(sent[0]?.to).toBe('alice@example.com');
    });

    it('should return false for invalid recipient email', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));
      expect(result).toBe(false);
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return false for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));
      expect(result).toBe(false);
    });

    it('should return false for recipient with spaces only', async () => {
      const result = await adapter.send(makePayload({ recipient: '   ' }));
      expect(result).toBe(false);
    });

    it('should include from address in sent email', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent[0]?.from).toBe('TaskFlow Pro <noreply@taskflowpro.com>');
    });

    it('should use custom config when provided', async () => {
      const custom = new EmailAdapter({
        fromAddress: 'support@myapp.com',
        fromName: 'My App',
      });

      await custom.send(makePayload());

      const sent = custom.getSentEmails();
      expect(sent[0]?.from).toBe('My App <support@myapp.com>');
    });

    it('should include rendered HTML in sent email', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent[0]?.html).toContain('<h2');
      expect(sent[0]?.html).toContain('Order Confirmation');
    });

    it('should record sentAt timestamp', async () => {
      const before = new Date();
      await adapter.send(makePayload());
      const after = new Date();

      const sent = adapter.getSentEmails();
      expect(sent[0]?.sentAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(sent[0]?.sentAt.getTime()).toBeLessThanOrEqual(after.getTime());
    });
  });

  describe('renderTemplate', () => {
    it('should render order_confirmation template with order ID', () => {
      const html = adapter.renderTemplate(makePayload());
      expect(html).toContain('Order Confirmation');
      expect(html).toContain('order-1');
      expect(html).toContain(makePayload().body);
    });

    it('should render order_status_update template', () => {
      const html = adapter.renderTemplate(
        makePayload({
          notificationType: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
          metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
        }),
      );
      expect(html).toContain('Order Status Update');
      expect(html).toContain('confirmed');
    });

    it('should render user_welcome template', () => {
      const html = adapter.renderTemplate(
        makePayload({
          notificationType: 'user_welcome',
          subject: 'Welcome to TaskFlow Pro',
          body: 'Welcome, Alice! Your account has been created.',
        }),
      );
      expect(html).toContain('Welcome to TaskFlow Pro');
      expect(html).toContain('get started');
    });

    it('should render user_updated template', () => {
      const html = adapter.renderTemplate(
        makePayload({
          notificationType: 'user_updated',
          subject: 'Account Updated',
          body: 'Your account has been updated.',
        }),
      );
      expect(html).toContain('Account Updated');
      expect(html).toContain('Your account has been updated.');
    });
  });

  describe('resolveRecipient', () => {
    it('should return lowercased email for valid address', () => {
      const result = adapter.resolveRecipient(makePayload({ recipient: 'USER@Example.COM' }));
      expect(result).toBe('user@example.com');
    });

    it('should return null for invalid email', () => {
      expect(adapter.resolveRecipient(makePayload({ recipient: 'bad' }))).toBeNull();
    });

    it('should return null for email without domain', () => {
      expect(adapter.resolveRecipient(makePayload({ recipient: 'user@' }))).toBeNull();
    });

    it('should return null for email without local part', () => {
      expect(adapter.resolveRecipient(makePayload({ recipient: '@example.com' }))).toBeNull();
    });

    it('should trim whitespace from recipient', () => {
      const result = adapter.resolveRecipient(makePayload({ recipient: '  alice@example.com  ' }));
      expect(result).toBe('alice@example.com');
    });
  });

  describe('channel', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should return a copy of sent emails', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentEmails();
      const second = adapter.getSentEmails();
      expect(first).toEqual(second);
      expect(first).not.toBe(second);
    });

    it('should clear all sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

